var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"커흑?!","JPN":"がはっ！！","ENG":"Kgh?!","TWN":"咳？！"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L6_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"셰나에 비해 기동성과 치명성은 미흡하군요.","JPN":"シェナに比べて機動力と危険性が足りませんね。","ENG":"You lack movement speed and lethality compared to Shena.","TWN":"你的靈活度和攻擊性都不及世娜。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L7_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"그 여우 같은 애랑 비교하지 말아 줄래? 무척 불쾌하거든?","JPN":"あの女狐と比べないでくれる？　気分が悪いわ！","ENG":"Stop comparing me to that vixen. It's annoying, you know.","TWN":"可以不要拿我和那個狐狸精相提並論嗎？感覺很差呢。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"아뇨. 불필요한 교전 형태로 전환하지 않게 해 줘서 감사하다는 뜻입니다, 침식체.","JPN":"いいえ。不要に交戦形態にならずに済むことに対して感謝を述べているだけです、侵食体。","ENG":"I merely meant to thank you for saving me the energy of converting into combat mode, C.O.","TWN":"不，我是在感謝你，因為這樣我就沒必要轉換成交戰形態。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"고철 따위가 감히…!","JPN":"鉄くずごときがよくも……！","ENG":"You piece of scrap metal...!","TWN":"你這個破銅爛鐵……！"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"시무르그의 프레임만 아니었으면 넌 상대해 줄 가치도 없었어!","JPN":"シムルグのフレームじゃなかったら、お前は相手する価値もなかったわよ！","ENG":"You wouldn't be able to stand a chance if it weren't for Simurgh's frame!","TWN":"要不是有西摩格的軀殼，你連讓我親自出手的資格都沒有！"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"현실성 없는 조건을 설정해서 도출한 결과는 무의미하다는 것도 이해 못합니까?","JPN":"現実性のない条件を設定して導いた結論は無意味だということも理解できないんですか？","ENG":"Do you fail to comprehend that it is meaningless to estimate results based on unrealistic variables?","TWN":"用一個不實際的假設得出的結果是毫無意義的，你連這一點都不明白嗎？"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"순순히 자신의 성능적 결함을 인정하고 저항을 포기하십시오.","JPN":"大人しく自分の性能的欠陥を認め、抵抗を諦めてください。","ENG":"Accept your defective design and cease your resistance.","TWN":"我建議你趕快承認自己的性能缺陷，放棄抵抗。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"흥, 미안하지만 그건 어렵겠는걸.","JPN":"ふん、悪いけどそれはできないわ。","ENG":"Hmph. I'm afraid that's not going to happen.","TWN":"哼，很抱歉，辦不到。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"어디, 여기 모인 인간들을 상대로도 그렇게 무식하게 주먹을 휘두를 수 있나 볼까?","JPN":"ここに集まっている人間相手でも、そうやって乱暴に拳を振り回せるかしら？","ENG":"Let's see if you can swing your fists to all the humans here.","TWN":"我們就來看看，在這麼多人面前，你也可以毫不在乎地揮拳嗎？"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"호라이즌 씨! 연주를 하지 못하게 막아야 해요!","JPN":"ホライズンさん！　演奏を止めなければ！","ENG":"Horizon! We have to stop her from playing her instrument!","TWN":"地平線！不能讓她演奏！"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"흥분하지 말고 충격에 대비하십시오, 휴먼.","JPN":"落ち着いて。衝撃に備えてください、ヒューマン。","ENG":"Stay calm and prepare for impact, human.","TWN":"人類，不要激動，準備面對衝擊。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"충격이요?","JPN":"衝撃？","ENG":"Impact?","TWN":"衝擊？"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"꺄악!?","JPN":"きゃあっ！？","ENG":"Eeek!","TWN":"哎呀？！"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L27_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"지, 지진!?","JPN":"じ、地震！？","ENG":"A-an earthquake?!","TWN":"是，地震？！"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"모르스 씨야! 하늘에서 떨어졌어!","JPN":"モールスさんだ！　空から降ってきた！","ENG":"It's Mors! She just dropped from the sky!","TWN":"是莫爾斯！從天而降！"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"카르멘이로군. 뜻밖의 무훈을 세웠구나, 시무르그의 후예여.","JPN":"カルメンか。手柄だな、シムルグの後継者よ。","ENG":"It is Carmen. This act of valor is of great service to me, Heir of Simurgh.","TWN":"原來是卡門，你立下意料之外的功勞呢，西摩格的後裔。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_BIG"},{"id":"L34_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"제 계보는 진공관이지, 그런 특허 출원도 안 된 외산과는 무관합니다. 침식체.","JPN":"私の系譜は真空管であり、そんな特許申請もなされていない外産とは関係ありません。侵食体。","ENG":"I come from a line of diodes and have no connections to that patent-less foreign-made, C.O.","TWN":"我的族譜是真空管，我和那個連專利都沒有的洋貨一點關係都沒有，侵蝕體。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"예, 예하……?","JPN":"猊、猊下……？","ENG":"Y-your Eminence...?","TWN":"主…主教……？"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"안 본 사이 안색이 많이 좋아지셨네요. 그간 안녕하셨나요?","JPN":"お休みになっていられたからか、顔色がずいぶん良くなりましたね。お元気でしたか？","ENG":"You look a lot better than when I last saw you. How have you been?","TWN":"別來無恙，主教的氣色好很多呢。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"너희가 횡행하는데 내 어찌 휴식을 취하겠는가.","JPN":"貴様らが横行しているというのに安らかに休めるものか。","ENG":"How would one find peace when you lot are running rampant?","TWN":"你們如此橫行霸道，我要如何休息？"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"여기 너를 위해 예비된 단두대가 왔으니, 안식에 들도록 하라.","JPN":"ここに貴様のために準備された断頭台がある、安息に入れ。","ENG":"This guillotine has been reserved for you. You shall rest in peace.","TWN":"這是為你而準備的斷頭台，進入安息吧。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"우, 우후훗…. 그런 무서운 말씀 하지 마시고요.","JPN":"う、うふふっ……そんな怖いことを言わないでください。","ENG":"U-uhu huu... Don't be so harsh.","TWN":"呵呵呵……請不要說這麼嚇人的話。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"우선 그 도끼날부터 치워 주시지 않을래요?","JPN":"とりあえず、その斧を退かしてくれませんか？","ENG":"First, will you take your axe away from me?","TWN":"先把斧頭收起來吧？"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"정녕 그러하길 원한다면, 네 자신의 손으로 핵을 파괴하라.","JPN":"そう望むなら、貴様の手で自らの核を破壊せよ。","ENG":"If that is your wish, then you are to destroy your core with your own hands.","TWN":"要我收起斧頭，你就自行破壞你的核心吧。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그것이 네가 이제껏 저질러 온 기만과 악행을 근절할 방도일지니.","JPN":"それが貴様が犯してきた欺瞞や悪事の罪を根絶する方法だ。","ENG":"It is the way in which you can terminate your previous deceptions and wrongdoings.","TWN":"如此才能徹底根除你一直以來犯下的欺騙和惡行。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"핵을 파괴하라니요, 예하. 옛날에 그랬듯이 자비를 베풀어 주시어요.","JPN":"核を破壊って、猊下。昔のように大目に見てはいただけないでしょうか。","ENG":"Destroy my own core? Your Eminence, please, show me mercy like you have before.","TWN":"怎麼可以要我自行毀滅呢，主教。請主教行行好，就像以前一樣放過我吧。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"그런 요구는…… 너무하다고 생각하는데요!","JPN":"そんな要求は……あまりにも酷いじゃありませんか！","ENG":"I find that... to be too tall of an order!","TWN":"況且，您的要求……我個人覺得有點過分！"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"아윽!?","JPN":"あうっ！？","ENG":"Augh?!","TWN":"呃呃？！"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"빈틈을 노리고 반격할 생각이었으려나. 어떻게 마지막까지 그렇게 추잡스러울까.","JPN":"油断させて反撃するつもりだったのかしら。最後までとことん汚い奴ね。","ENG":"I guess you were trying to fight back as you saw an opening. How lowly of you, until the very end.","TWN":"想趁機反擊嗎？怎麼到最後都還是如此卑鄙。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L6_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"이……. 가축으로 삼지도 못할 실험체 주제에…….","JPN":"この……家畜にも劣る実験体の分際で……","ENG":"You... test subject that can't even be a pet...","TWN":"你……你這連寵物都不如的實驗體……"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"괜찮아. 머리에 총 맞는 한이 있어도 네 보살핌 같은 건 받기 싫거든.","JPN":"それが何だって言うの。あなたに世話されるくらいなら頭を銃で撃たれた方がマシよ。","ENG":"That's fine with me. I'd rather get shot in the head than be under your care.","TWN":"無所謂，與其被你當做寵物照顧，我倒不如給我自己的腦袋一槍。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"오히려 육아는 내가 너보다 한 수 위가 아니려나? 시궁쥐처럼 달아났던 패잔병 씨.","JPN":"それに、育児なら私の方がうまいと思うけど？　ドブネズミのように逃げた敗残兵さん。","ENG":"But it seems that I'm better at taking care of others. You're just a rat who ran away after losing.","TWN":"而且以育兒來說，我比你更擅長吧？你這個只會夾著尾巴逃跑的過街老鼠！"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"큭……!","JPN":"くっ……！","ENG":"Kgh...!","TWN":"呃……！"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"알렉스 씨, 제때 도착해 주셨네요.","JPN":"アレックスさん、ちょうどいいタイミングです！","ENG":"Alex, you arrived just in time.","TWN":"雅蕾克絲，你來得正好。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그렇다면 다행이네. 너무 늦지 않았을까 걱정했어.","JPN":"ならよかったわ。もう遅いんじゃないかって心配してたの。","ENG":"That's a relief. I was worried I'd be too late.","TWN":"那就好，我還擔心會太遲呢。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"영공 진입 허가가 그렇게 까탈스러운 줄 알았으면 미리 수속을 밟아 뒀을 겁니다.","JPN":"領空への進入許可があれほど面倒だとわかっていたら、あらかじめ手続きをしておいたのですが。","ENG":"We would've gone through the entry procedure beforehand if we knew that getting authorization for entering the airspace was so complicated.","TWN":"早知道要取得進入領空的許可這麼麻煩，我一定會提早跑流程。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"샤레이드에서 노르드나빅까지는 거리도 꽤나 되니 말이죠.","JPN":"シャレードからノルドナビックまではかなり距離もありますしね。","ENG":"Since it's quite far from Charade to Nordnavik.","TWN":"畢竟從查雷德到諾爾德萊比也蠻遠的。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그래서 이 침식체는 어떻게 처리할 겁니까?","JPN":"それで、この侵食体はどうしますか？","ENG":"So, what is our plan of action for this C.O.?","TWN":"現在該如何處理這個侵蝕體？"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"안식을 선사하겠다. 무릇 역병에 사로잡힌 자에게 예외는 없나니.","JPN":"安息を与える。疫病に犯された者に例外はない。","ENG":"It shall be granted eternal rest. As there are no exceptions regarding those who were consumed by the plague.","TWN":"我將賜予她安息，只要是被感染瘟疫的人都無一例外。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"다, 다가오지 마! 가까이 오면 할퀴어 버릴 줄 알아!","JPN":"こ、来ないで！　近づいたら引っ掻いてやるわ！","ENG":"S-stay back! I'm going to rip you all if you come any closer!","TWN":"別…別過來！再過來我就抓爛你！"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L26_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그만두십시오. 여기 있는 침식체나 저나 당신 손톱만 부러질 겁니다.","JPN":"やめることですね。ここにいる侵食体や私にそんなことをしてもあなたの爪が損傷するだけです。","ENG":"I would not do so if I were you. Regardless of whether you attack me or the C.O. here, your nails will be the only thing breaking.","TWN":"放棄吧，結果就是在場的侵蝕體或我會折斷你的手指。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"잠깐, 잠깐잠깐!","JPN":"ちょ、待って待って！","ENG":"Wait, wait wait!","TWN":"等等，等等！"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"둘이 쿵짝 맞아서 정해 버리면 어떡해! 다른 사람들 의견도 들어 봐야지!","JPN":"二人だけでとんとん拍子で決めないでよ！　他のみんなの意見も聞かないと！","ENG":"You can't just decide that by yourselves! You should listen to other people's opinions too!","TWN":"怎麼可以你們二個人自己做決定！也應該聽聽別人的意見吧！"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그나마 상식적인 감성을 가진 사람이 있어서 위안이네요.","JPN":"常識的な感性の持ち主がいてくれてほっとしました。","ENG":"I'm glad at least someone's being logical.","TWN":"幸好我們當中還有腦袋正常的人……"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"핵이 파괴되기 싫으면 말해 보세요, 카르멘.","JPN":"核が破壊されたくなければ言ってください、カルメン。","ENG":"If you don't want your core to be destroyed, tell us.","TWN":"卡門，你要是想保住核心就快說。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"네퀴티아가 지금 어디서 뭘 꾸미고 있는지.","JPN":"ネキティアは今どこで何を企んでいるのか。","ENG":"Where is Nequitia and what is she up to?","TWN":"莉奎蒂亞究竟在哪裡？她在計畫什麼？"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"흥…. 답지 않게 기고만장하네. 꼬마 중사님.","JPN":"ふん……急に態度が大きくなったわね、チビ軍曹さん。","ENG":"Hmph... You're very conceited, Sergeant Kiddo. It's not like you.","TWN":"哼…看你小小一隻，口氣倒是蠻大的嘛。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"그렇게 목소리 깔고 물어 보면 내가 겁먹을 줄 알았니?","JPN":"そんなふうに低い声を出せば私が怖がると思った？","ENG":"Did you think you could scare me by talking in a deeper voice?","TWN":"你以為壓低嗓門我就會怕你嗎？"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"하긴, 저도 대화가 안 통하는 상대에게 말 걸고 있으려니까 자괴감 드네요.","JPN":"確かに、私も話が通じない相手に話かけていたら、自分が嫌になってきました。","ENG":"I suppose it's embarrassing to keep talking to someone I can't get through to.","TWN":"也是，我也覺得和一個聽不懂人話的人說話有點尷尬……"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"하지만 그거 아세요? 어차피 선택권은 없다는 거.","JPN":"でも知っていますか？　どのみち選択肢はないんです。","ENG":"But did you know? You don't have a choice.","TWN":"不過你知道嗎？你根本沒得選。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"설마 날 협박하는 거야?","JPN":"もしかして脅迫しているの？","ENG":"Are you threatening me?","TWN":"你是在威脅我嗎？"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L44_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"명예훈장 수훈자라고 으스대더니, 하나도 명예롭지 못한 짓 아니니?","JPN":"名誉勲章の受勲者とか言っていたわりには、全然名誉ある態度じゃないわよ？","ENG":"For someone who received the Medal of Honor, how very dishonorable of you.","TWN":"身為一個授勳的軍人，這麼做不會有損名譽嗎？"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"어차피 전 사람들이 떠드는 명예로운 전투는 한 번도 해 본 적 없는 걸요.","JPN":"どうせ私はみんなが言っているような名誉ある戦いなんてしたことありません。","ENG":"I mean, I've never fought in an honorable battle that people always talk about.","TWN":"反正我本來就沒打過那些所謂的榮譽之戰。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"살아남는 게 중요하지, 정정당당하게 싸우면 하늘에서 총알이라도 떨어진대요?","JPN":"生き残ることが大事なんです。正々堂々と戦ったところで空から補給品は落ちてこないんですよ？","ENG":"What's important is living to see another day. It's not like we get more ammunition for playing fair.","TWN":"最重要的是活下來，正大光明地作戰就保證能活嗎？"},"stage":{"bg":"CAMP_01","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L49_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"좋아. 대신에 나와 거래를 했으면 해.","JPN":"いいわ。でもその代わり、私と取引してちょうだい。","ENG":"Fine. Then I want to make a trade.","TWN":"好，那我和你做個交易。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"중사님, 기다려.","JPN":"待って、軍曹。","ENG":"Sergeant, wait.","TWN":"中士，先等一下。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"혹시 그림자의 말을 믿는 걸까? 그렇다면 다시 생각하는 편이 좋을 거야.","JPN":"まさかシャドウの言葉を信じるつもりじゃないわよね？　だったら考え直した方がいいわよ。","ENG":"You're not going to trust a Shadow, are you? If so, you better reconsider.","TWN":"你相信那個暗影說的話嗎？你要不要再想一下。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"저도 부전대장님과 같은 생각입니다.","JPN":"私も副戦隊長殿と同じ考えです。","ENG":"I agree with the Deputy Commander.","TWN":"我的想法和副戰隊長一樣。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"하지만…. 이대로라면 죽을 때까지 네퀴티아를 두려워하면서 지내야 할 수도 있잖아요.","JPN":"ですが……このままでは死ぬまでネキティアに怯えて暮らすことになるかもしれないんです。","ENG":"But... we might end up having to live in fear of Nequitia until the day we die.","TWN":"但是…不這麼做的話，就只能每天過著擔心莉奎蒂亞不知道什麼時候會出現的日子。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L9_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"그건…….","JPN":"それは……","ENG":"I...","TWN":"這……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"……흐음.","JPN":"……ふーん。","ENG":"...Hmm.","TWN":"……嗯嗯。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"말해 봐요. 거래 조건이 뭔지.","JPN":"言ってください。取引の条件を。","ENG":"Tell me. What are your conditions?","TWN":"說吧，交易條件是什麼？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"내 요구는 간단해. 항복할 테니까 포로로 대접해 줘.","JPN":"私からの要求は簡単よ。降伏するから人質として扱ってちょうだい。","ENG":"It's simple. I'll surrender, and I want you to treat me as a captive.","TWN":"我的要求很簡單。我願意投降，但你們要把我當俘虜對待。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"항복…?","JPN":"降伏……？","ENG":"Surrender...?","TWN":"投降……？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"미쳤습니까, 침식체?","JPN":"正気ですか、侵食体？","ENG":"Are you insane, C.O.?","TWN":"侵蝕體，你的腦袋壞掉嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"진심이야. 여기서 더 반항해 봤자 예하에게 핵이 쪼개지기만 할 테니까.","JPN":"本気よ。これ以上反抗したところで、猊下に核を破壊されるだけだし。","ENG":"I'm serious. Her Eminence will destroy my core if I try to do anything.","TWN":"我是說真的，再繼續反抗下去，下場就是主教會毀掉我的核心。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"내 안전을 보장해 주면, 너희들이 원하는 정보를 줄게.","JPN":"私の身の安全を保証してくれれば、知りたいことを教えるわ。","ENG":"If you can guarantee my safety, I will give you information.","TWN":"只要你們能保障我的安全，我就把你們想要的情報說出來。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"애초에, 내가 그 늙은 인간이 어디 있는지도 모르고 여기 왔을 것 같아?","JPN":"そもそも、私があの老婆の所在も知らずにここに来たと思ってるの？","ENG":"Do you think I'd come here if I didn't know where that old human was?","TWN":"如果我連那個老太婆在哪裡都不知道，我哪敢貿然來到這裡？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};